package example_00;

public class Hello {
	public static int sum(int n, int m) {
		return n + m;
	}

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a = 5;
		int b = 7;
		int c = sum(a, b);
		char d;
		String e;
		
		d = 'H';
		e = "Hello, World!";
		
		System.out.println(a);
		System.out.println(b);
		System.out.println(c);
		System.out.println(d);
		System.out.println(e);
	}

}
